#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
    controller->now_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_pump_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_pump_on = controller->pump_on;
    previous_state = controller->state;

    /* Check for timeout - fail safe if no valid sensor within 1000ms */
    bool timed_out = false;
    if (controller->has_valid_sensor && input.kind != CONTROLLER_INPUT_LEVEL) {
        /* Input is not a new sensor reading, check for timeout */
        uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            timed_out = true;
        }
    }

    switch (input.kind) {
    case CONTROLLER_INPUT_LEVEL:
        /* Valid level reading arrived */
        controller->has_valid_sensor = true;
        controller->last_level = input.level;
        controller->last_valid_sensor_ms = input.now_ms;
        controller->now_ms = input.now_ms;

        /* Apply control policy based on current level */
        if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
            /* Low level: turn pump ON */
            controller_set_safe_off(controller);
            controller->pump_on = true;
            controller->state = CONTROLLER_STATE_PUMPING;
        } else if (input.level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            /* High level: turn pump OFF */
            controller_set_safe_off(controller);
            controller->pump_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
        } else {
            /* Mid-band (30-80): hold previous safe output */
            /* Don't change state, keep existing pump_on value */
        }

        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Sensor timeout event - fail safe */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        timed_out = true;
        break;
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Invalid level input - fail safe */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        timed_out = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No valid input - check for timeout if we have stale data */
        if (controller->has_valid_sensor) {
            /* Check if we're past the timeout threshold with stale data */
            uint32_t elapsed_ms = controller->now_ms - controller->last_valid_sensor_ms;
            if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
                timed_out = true;
                controller_set_safe_off(controller);
            }
        } else {
            /* No valid sensor yet, stay safe off */
            controller_set_safe_off(controller);
        }
        break;
    }

    /* Mark output as changed if pump state or state changed */
    output.pump_on = controller->pump_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_pump_on != controller->pump_on) || 
                      (previous_state != controller->state);

    /* Mark timeout in output if it occurred */
    output.timed_out = timed_out;

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PUMPING:
        return "STATE PUMPING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}
